import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import moment from 'moment';
import toast from 'react-hot-toast';
import { FaHeart, FaRegHeart, FaBell, FaBellSlash, FaUserCircle } from 'react-icons/fa';

export default function VideoPlayer() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [video, setVideo] = useState(null);
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState('');
    const [isLiked, setIsLiked] = useState(false);
    const [likesCount, setLikesCount] = useState(0);
    const [isSubscribed, setIsSubscribed] = useState(false);
    const [subCount, setSubCount] = useState(0);
    const [activeTab, setActiveTab] = useState('chat');

    useEffect(() => {
        fetchVideo();
        fetchComments();
    }, [id]);

    const fetchVideo = async () => {
        try {
            const response = await axios.get(`/videos/${id}/`);
            setVideo(response.data);
            setIsLiked(response.data.is_liked || false);
            setLikesCount(response.data.like_count || 0);
            setSubCount(response.data.author?.subscriber_count || 0);
        } catch (error) {
            console.error('Error fetching video:', error);
            navigate('/');
        }
    };

    const fetchComments = async () => {
        try {
            const response = await axios.get(`/videos/${id}/comments/`);
            setComments(response.data);
        } catch (error) {
            console.error('Error fetching comments:', error);
        }
    };

    const handleLike = async () => {
        if (!user) { toast.error('Войдите чтобы поставить лайк'); return; }
        try {
            const response = await axios.post(`/videos/${id}/like/`);
            setIsLiked(response.data.status === 'liked');
            setLikesCount(response.data.count);
        } catch (error) { toast.error('Ошибка'); }
    };

    const handleSubscribe = async () => {
        if (!user) { toast.error('Войдите чтобы подписаться'); return; }
        try {
            const response = await axios.post(`/users/${video.author.id}/subscribe/`);
            setIsSubscribed(response.data.status === 'subscribed');
            setSubCount(response.data.count);
            toast.success(response.data.status === 'subscribed' ? 'Подписан' : 'Отписан');
        } catch (error) { toast.error('Ошибка'); }
    };

    const handleComment = async (e) => {
        e.preventDefault();
        if (!user) { toast.error('Войдите чтобы оставить комментарий'); return; }
        if (!newComment.trim()) return;
        try {
            await axios.post(`/videos/${id}/comments/`, { text: newComment });
            setNewComment('');
            fetchComments();
            toast.success('Комментарий добавлен');
        } catch (error) { toast.error('Ошибка'); }
    };

    if (!video) return <div className="flex justify-center items-center h-screen text-white">Загрузка...</div>;

    return (
        <div className="pt-16 bg-black min-h-screen">
            <div className="container mx-auto px-4 py-8">
                <div className="flex flex-col lg:flex-row gap-8">
                    <div className="lg:w-3/4">
                        <video controls autoPlay className="w-full rounded-xl" src={video.video_file} />

                        <div className="mt-4">
                            <h1 className="text-2xl font-bold text-white">{video.title}</h1>
                            <div className="flex items-center justify-between mt-4 pb-4 border-b border-gray-800">
                                <Link to={`/profile/${video.author?.username}`} className="flex items-center space-x-3 group">
                                    <div className="figma-author-avatar w-10 h-10 text-lg">
                                        {video.author?.username?.[0]?.toUpperCase()}
                                    </div>
                                    <div>
                                        <p className="font-semibold text-white group-hover:text-purple-400">{video.author?.username}</p>
                                        <p className="text-sm text-gray-400">{subCount} подписчиков</p>
                                    </div>
                                </Link>
                                <div className="flex items-center space-x-3">
                                    <button onClick={handleLike} className={`flex items-center space-x-2 px-4 py-2 rounded-full transition ${isLiked ? 'bg-red-600 text-white' : 'bg-gray-800 text-gray-300 hover:bg-gray-700'}`}>
                                        {isLiked ? <FaHeart /> : <FaRegHeart />}
                                        <span>{likesCount}</span>
                                    </button>
                                    <button onClick={handleSubscribe} className={`flex items-center space-x-2 px-4 py-2 rounded-full transition ${isSubscribed ? 'bg-gray-700' : 'bg-red-600'} text-white`}>
                                        {isSubscribed ? <FaBellSlash /> : <FaBell />}
                                        <span>{isSubscribed ? 'Отписаться' : 'Подписаться'}</span>
                                    </button>
                                </div>
                            </div>

                            <div className="mt-4 p-4 bg-gray-900 rounded-xl">
                                <p className="text-gray-300">{video.description || 'Нет описания'}</p>
                                <p className="text-sm text-gray-500 mt-2">{video.views} просмотров</p>
                            </div>

                            {/* Figma чат */}
                            <div className="figma-chat mt-8">
                                <div className="figma-chat-tabs">
                                    <div className={`figma-chat-tab ${activeTab === 'chat' ? 'active' : ''}`} onClick={() => setActiveTab('chat')}>
                                        Чат
                                    </div>
                                    <div className={`figma-chat-tab ${activeTab === 'qa' ? 'active' : ''}`} onClick={() => setActiveTab('qa')}>
                                        Вопрос / ответ
                                    </div>
                                </div>

                                <div className="space-y-2 max-h-96 overflow-y-auto mb-4">
                                    {comments.map(comment => (
                                        <div key={comment.id} className="figma-message">
                                            <div className="figma-message-left">
                                                <div className="figma-message-name">{comment.user?.username}</div>
                                                <div className="figma-message-text">{comment.text}</div>
                                            </div>
                                            <div className="text-xs text-gray-500">{moment(comment.created_at).fromNow()}</div>
                                        </div>
                                    ))}
                                    {comments.length === 0 && (
                                        <div className="text-center text-gray-500 py-8">Нет комментариев. Будьте первым!</div>
                                    )}
                                </div>

                                <form onSubmit={handleComment} className="flex gap-3">
                                    <input type="text" value={newComment} onChange={e => setNewComment(e.target.value)} placeholder="Напишите комментарий..." className="figma-input flex-1" />
                                    <button type="submit" className="figma-button">Отправить</button>
                                </form>
                            </div>
                        </div>
                    </div>

                    <div className="lg:w-1/4">
                        <h3 className="text-xl font-bold text-white mb-4">🎬 Рекомендации</h3>
                        <div className="text-gray-500 text-center py-8">Скоро здесь будут рекомендации</div>
                    </div>
                </div>
            </div>
        </div>
    );
}
